// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Rich_Product_Sheet_Message
// DESC: Visualizzazione completa dati estratti e blocco UI
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero dati dal blocco prodotto
const block = item.new_product_block || {};
const ident = block.identity || {};
const price = block.pricing || {};
const ops = block.operations || {};
const marketing = block.relations?.marketing_info || {};
const owner = item.owner_data || {};

const chatId = item.chat_id || (item.body.callback_query && item.body.callback_query.message.chat.id);
const messageId = item.message_id || (item.body.callback_query && item.body.callback_query.message.message_id);

// 2. Rilevamento Lingua
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "📝 <b>IDENTITÀ PROCEDURA ESTRATTA</b>",
    label_name: "📋 Nome:",
    label_type: "🗂️ Tipo:",
    label_desc: "📖 Descrizione:",
    label_price: "💰 Valore Commerciale:",
    label_time: "⏳ Esecuzione stimata:",
    label_target: "👥 Target:",
    label_tags: "🏷️ Tag:",
    next_phase: "⚙️ <b>PROSSIMA FASE: Scrittura Tecnica del Blueprint</b>",
    warning: "⚠️ <b>Nota:</b> Questa operazione è complessa e richiede <b>qualche minuto</b> per essere completata.\n\n<i>Il sistema rimarrà impegnato fino al termine della scrittura tecnica. Attendi senza inviare altri comandi.</i>"
  },
  en: {
    title: "📝 <b>PROCEDURE IDENTITY EXTRACTED</b>",
    label_name: "📋 Name:",
    label_type: "🗂️ Type:",
    label_desc: "📖 Description:",
    label_price: "💰 Commercial Value:",
    label_time: "⏳ Est. Execution:",
    label_target: "👥 Target:",
    label_tags: "🏷️ Tags:",
    next_phase: "⚙️ <b>NEXT PHASE: Technical Blueprint Writing</b>",
    warning: "⚠️ <b>Note:</b> This is a complex operation and will take <b>a few minutes</b> to complete.\n\n<i>The system will remain busy until the technical writing is finished. Please wait and do not send other commands.</i>"
  }
}[lang];

// 3. Costruzione dinamica del corpo (Solo dati presenti)
let rows = [];
rows.push(`${t.label_name} <b>${ident.item_name}</b>`);
rows.push(`${t.label_type} <code>${ident.item_type}</code>`);

if (ident.description?.long) {
    rows.push(`\n${t.label_desc}\n<i>${ident.description.long}</i>\n`);
}

// Mostra Prezzo solo se > 0
if (price.base_price > 0) {
    rows.push(`${t.label_price} <b>${price.base_price} ${price.currency}</b>`);
}

// Mostra Tempo solo se valorizzato
if (ops.fulfillment_time?.value) {
    rows.push(`${t.label_time} <b>${ops.fulfillment_time.value} ${ops.fulfillment_time.unit}</b>`);
}

// Target Audience
if (marketing.target_audience_tags?.length > 0) {
    rows.push(`${t.label_target} <code>${marketing.target_audience_tags.join(", ")}</code>`);
}

// Tag tecnici
if (ident.tags?.length > 0) {
    rows.push(`${t.label_tags} #${ident.tags.join(" #")}`);
}

// 4. Formattazione finale del messaggio
const messageText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${rows.join("\n")}

━━━━━━━━━━━━━━━━━━━━
${t.next_phase}

${t.warning}`;

// 5. Payload Telegram
return [{
  json: {
    ...item,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: messageText,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: [] }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_HoneyPot_Reducer_Fit
// DESC: Allinea l'input per il nodo HoneyPot_Context_Reducer
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Validazione HoneyPot
// Se l'HoneyPot non ha frammenti, inizializziamo un array vuoto per evitare crash
const honeyPot = item.HoneyPot || {};
let fragments = honeyPot.knowledge_fragments || [];

// FIX: Il Reducer v3.0 cerca "frag.title", ma nel tuo JSON hai "fragment_id".
// Mappiamo fragment_id su title per permettere allo scoring di funzionare.
fragments = fragments.map(f => ({
    ...f,
    title: f.title || f.fragment_id || "Frammento Conoscenza"
}));

// 2. Validazione New Product Block
// Ci assicuriamo che la struttura identity esista
const newProductBlock = item.new_product_block || {};
if (!newProductBlock.identity) {
    throw new Error("Errore: new_product_block.identity mancante nell'input.");
}

// 3. Preparazione Output "Fit"
// Restituiamo l'oggetto completo ma con i frammenti "corretti" per il Reducer
return [{
    json: {
        ...item,
        HoneyPot: {
            ...honeyPot,
            knowledge_fragments: fragments
        }
    }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Final_Blueprint_Execution_Message
// DESC: Mostra il Blueprint finale e genera i tasti WebApp per gli step
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero Dati Core
const blueprint = item.Final_Blueprint || {};
const product = item.Final_Product || {};
const owner = item.owner_data || {};

const vat = product.owner_instance_id;
const userId = vat; // Assumiamo coincidano per l'owner
const chatId = owner.chat_id;
const sopId = blueprint.service_sku;

// Recupero la base URL dalla variabile dinamica
const baseUrl = item.urlMiniApp; 

// 2. Rilevamento Lingua
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "✅ <b>BLUEPRINT ATTIVATO</b>",
    body: `La procedura <b>"${blueprint.blueprint_name}"</b> è ora operativa.`,
    desc: blueprint.blueprint_description,
    header_steps: "🚀 <b>STEP DI CERTIFICAZIONE DISPONIBILI:</b>",
    btn_back: "⬅️ Torna al Catalogo",
    evidence_labels: {
        "IMAGE": "📸 Foto",
        "FILE": "📄 Documento",
        "TEXT": "📝 Testo/Validazione"
    }
  },
  en: {
    title: "✅ <b>BLUEPRINT ACTIVATED</b>",
    body: `The procedure <b>"${blueprint.blueprint_name}"</b> is now operational.`,
    desc: blueprint.blueprint_description,
    header_steps: "🚀 <b>AVAILABLE CERTIFICATION STEPS:</b>",
    btn_back: "⬅️ Back to Catalog",
    evidence_labels: {
        "IMAGE": "📸 Photo",
        "FILE": "📄 Document",
        "TEXT": "📝 Text/Validation"
    }
  }
}[lang];

// 3. Analisi Dinamica degli Step per generare la pulsantiera
let inlineKeyboard = [];
let stepsSummary = "";

if (blueprint.stages) {
    blueprint.stages.forEach(stage => {
        stage.steps.forEach(step => {
            // Se lo step richiede un controllo di qualità (Certificazione)
            if (step.quality_check && step.quality_check.is_required) {
                const evType = step.quality_check.evidence_type || "IMAGE";
                const labelIcon = t.evidence_labels[evType] || "✔️";

                // Costruzione URL WebApp: rimosso user_id, vat e chat_id come da regola
                const fullWebAppUrl = `${baseUrl}certificator.html?sop_id=${sopId}&step_id=${step.step_id}&evidence_type=${evType}`;

                // Aggiungiamo il pulsante alla tastiera
                inlineKeyboard.push([{
                    text: `${labelIcon}: ${step.step_name}`,
                    web_app: { url: fullWebAppUrl }
                }]);

                // Aggiungiamo lo step al riepilogo testuale
                stepsSummary += `• <b>${step.step_name}</b> (${evType})\n`;
            }
        });
    });
}

// 4. Aggiunta tasto di ritorno in fondo
inlineKeyboard.push([{ text: t.btn_back, callback_data: `get_active_sop_${product.identity.category}` }]);

// 5. Formattazione finale del messaggio
const messageText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${t.body}

<i>${t.desc}</i>

${t.header_steps}
${stepsSummary}
━━━━━━━━━━━━━━━━━━━━
👇 <b>Clicca su uno step per inviare l'evidenza:</b>`;

// 6. Output per Telegram (EditMessageText)
const messageId = item.message_id || (item.body.callback_query && item.body.callback_query.message.message_id);

return [{
  json: {
    ...item,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: messageText,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: inlineKeyboard
      }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Context_Preparer_With_UI_Freeze
// DESC: Prepara dati per Reducer v3.0 + Messaggio di Attesa
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero Dati Core
const owner = item.owner_data || {};
const catalog = item.service_catalog_setup || {};
const cbData = item.body.callback_query.data;
const chatId = item.body.callback_query.message.chat.id;
const messageId = item.body.callback_query.message.message_id;

// 2. Estrazione ID (Ghost & Category) per il Reducer v3.0
const ghostId = cbData.includes('confirm_blueprint_build_') 
    ? cbData.replace('confirm_blueprint_build_', '') 
    : null;

let foundCatId = null;
let procedureName = "Procedura";

if (catalog.categories && ghostId) {
    for (const cat of catalog.categories) {
        const match = cat.subcategories.find(sub => sub.callback_data === ghostId);
        if (match) {
            foundCatId = cat.callback_data;
            procedureName = match.short_name || match.name;
            break;
        }
    }
}

// 3. Localizzazione Messaggio di Attesa
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "⏳ <b>ELABORAZIONE IN CORSO...</b>",
    body: `L'attivazione del Blueprint per <b>"${procedureName}"</b> richiede qualche minuto.\n\n⚠️ In questa fase il sistema è impegnato: <b>non è possibile eseguire altre operazioni</b>.\n\nRiceverai una notifica non appena il processo sarà completato.`
  },
  en: {
    title: "⏳ <b>PROCESSING...</b>",
    body: `Activating the Blueprint for <b>"${procedureName}"</b> will take a few minutes.\n\n⚠️ The system is busy right now: <b>no other operations can be performed</b>.\n\nYou will receive a notification once the process is complete.`
  }
}[lang];

// 4. Costruzione Payload Telegram (Edit + Rimozione Tastiera)
const telegramPayload = {
  method: "editMessageText",
  chat_id: chatId,
  message_id: messageId,
  text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n${t.body}`,
  parse_mode: "HTML",
  reply_markup: {
    inline_keyboard: [] // Rimuove tutti i pulsanti
  }
};

// 5. Output con Fit perfetto per Context_Reducer v3.0
return [{
  json: {
    ...item,
    user_request: {
      category_id: foundCatId,
      ghost_id: ghostId
    },
    telegramApiPayload: telegramPayload // Per il nodo HTTP Request immediato
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Final_MKT_Forge_Success_Message
// DESC: Messaggio finale Post-Forgia con tasti operativi Marketing
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const owner = item.owner_data || {};
const ghost_id = item.user_request?.ghost_id; // Recuperato dal preparatore (SVC_...)
const baseUrl = item.urlMiniApp;

// --- 1. CONFIGURAZIONE SICUREZZA ASH (Identica al tuo nodo GET) ---
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const WEBHOOK_ID = 'ef4aece4-9ec0-4026-a7a7-328562bcbdf6';
const chatId = owner.chat_id.toString();
const timestamp = Date.now().toString();
const payload = `${chatId}|${timestamp}|${WEBHOOK_ID}`;

function generateSignature(str, key) {
    let hash = 0;
    const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const signature = generateSignature(payload, SECRET_KEY);
const ash = `${Buffer.from(payload).toString('base64')}.${signature}`;

// --- 2. RECUPERO INFO ASSET DAL CATALOGO ---
const catalog = item.service_catalog_setup?.categories || [];
let asset = { name: ghost_id, catId: "" };

for (const cat of catalog) {
    const match = cat.subcategories?.find(s => s.callback_data === ghost_id);
    if (match) { 
        asset = { name: match.name, catId: cat.callback_data }; 
        break; 
    }
}

// --- 3. COSTRUZIONE MESSAGGIO E TASTIERA ---
// Usiamo i testi e i callback_data ESATTI del tuo Marketing Hub
let msgText = `✨ <b>INGEGNERIA COMPLETATA</b>\nL'asset è ora mappato e pronto all'uso.\n\n🎯 <b>TARGET:</b>\n<code>${asset.name.toUpperCase()}</code>\n━━━━━━━━━━━━━━━━━━━━\nScegli l'azione di proiezione esterna:`;

let buttons = [
    // Tasto WebApp con ASH generato sopra
    [{ text: "⚙️ EDITA KNOWLEDGE", web_app: { url: `${baseUrl}edit-knowledge.html?sop_id=${ghost_id}&ash=${ash}` } }],

    // Tasti Azione Marketing (m_mkt_ask_...)
    [{ text: "📝 Post AI", callback_data: `m_mkt_ask_post_${ghost_id}` }],
    [{ text: "🌐 Deploy SAP", callback_data: `m_mkt_ask_sap_${ghost_id}` }],
    [{ text: "📣 Broadcast", callback_data: `m_mkt_ask_broad_${ghost_id}` }]
];

// Tasto Indietro alla lista di categoria
buttons.push([{ text: "⬅️ Torna alla Lista", callback_data: `m_mkt_list_${asset.catId}` }]);

// --- 4. OUTPUT PER TELEGRAM ---
const messageId = item.body?.callback_query?.message?.message_id || item.telegramApiPayload?.message_id;

return [{
  json: {
    ...item,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: owner.chat_id,
      message_id: messageId,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: buttons
      }
    }
  }
}];

